package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testGetCommentMarker() {
        // Given
        Character expected = '#';

        // When
        Character actual = csvFormat.getCommentMarker();

        // Then
        assertEquals(expected, actual);
    }

    @Test
    public void testGetCommentMarkerWhenNull() {
        // Given
        CSVFormat csvFormatMock = mock(CSVFormat.class);
        when(csvFormatMock.getCommentMarker()).thenReturn(null);

        // When
        Character actual = csvFormatMock.getCommentMarker();

        // Then
        assertEquals(null, actual);
    }
}
